import {useRef, useEffect, useCallback, useMemo} from 'react'
import {isPreact, isReactNative} from '../../is.macro'
import {handleRefs, normalizeArrowKey, callAllEventHandlers} from '../../utils'
import {
  useA11yMessageSetter,
  useMouseAndTouchTracker,
  useGetterPropsCalledChecker,
  useLatestRef,
  useScrollIntoView,
  useControlPropsValidator,
  useElementIds,
  getItemAndIndex,
} from '../utils'
import {
  getInitialState,
  defaultProps,
  useControlledReducer,
  validatePropTypes,
} from './utils'
import downshiftUseComboboxReducer from './reducer'
import * as stateChangeTypes from './stateChangeTypes'

useCombobox.stateChangeTypes = stateChangeTypes

function useCombobox(userProps = {}) {
  validatePropTypes(userProps, useCombobox)
  // Props defaults and destructuring.
  const props = {
    ...defaultProps,
    ...userProps,
  }
  const {
    initialIsOpen,
    defaultIsOpen,
    items,
    scrollIntoView,
    environment,
    getA11yStatusMessage,
    getA11ySelectionMessage,
    itemToString,
  } = props
  // Initial state depending on controlled props.
  const initialState = getInitialState(props)
  const [state, dispatch] = useControlledReducer(
    downshiftUseComboboxReducer,
    initialState,
    props,
  )
  const {isOpen, highlightedIndex, selectedItem, inputValue} = state

  // Element refs.
  const menuRef = useRef(null)
  const itemRefs = useRef({})
  const inputRef = useRef(null)
  const toggleButtonRef = useRef(null)
  const isInitialMountRef = useRef(true)
  // prevent id re-generation between renders.
  const elementIds = useElementIds(props)
  // used to keep track of how many items we had on previous cycle.
  const previousResultCountRef = useRef()
  // utility callback to get item element.
  const latest = useLatestRef({state, props})

  const getItemNodeFromIndex = useCallback(
    index => itemRefs.current[elementIds.getItemId(index)],
    [elementIds],
  )

  // Effects.
  // Sets a11y status message on changes in state.
  useA11yMessageSetter(
    getA11yStatusMessage,
    [isOpen, highlightedIndex, inputValue, items],
    {
      isInitialMount: isInitialMountRef.current,
      previousResultCount: previousResultCountRef.current,
      items,
      environment,
      itemToString,
      ...state,
    },
  )
  // Sets a11y status message on changes in selectedItem.
  useA11yMessageSetter(getA11ySelectionMessage, [selectedItem], {
    isInitialMount: isInitialMountRef.current,
    previousResultCount: previousResultCountRef.current,
    items,
    environment,
    itemToString,
    ...state,
  })
  // Scroll on highlighted item if change comes from keyboard.
  const shouldScrollRef = useScrollIntoView({
    menuElement: menuRef.current,
    highlightedIndex,
    isOpen,
    itemRefs,
    scrollIntoView,
    getItemNodeFromIndex,
  })
  useControlPropsValidator({
    isInitialMount: isInitialMountRef.current,
    props,
    state,
  })
  // Focus the input on first render if required.
  useEffect(() => {
    const focusOnOpen = initialIsOpen || defaultIsOpen || isOpen

    if (focusOnOpen && inputRef.current) {
      inputRef.current.focus()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])
  useEffect(() => {
    if (isInitialMountRef.current) {
      return
    }

    previousResultCountRef.current = items.length
  })
  // Add mouse/touch events to document.
  const mouseAndTouchTrackersRef = useMouseAndTouchTracker(
    isOpen,
    [inputRef, menuRef, toggleButtonRef],
    environment,
    () => {
      dispatch({
        type: stateChangeTypes.InputBlur,
        selectItem: false,
      })
    },
  )
  const setGetterPropCallInfo = useGetterPropsCalledChecker(
    'getInputProps',
    'getMenuProps',
  )
  // Make initial ref false.
  useEffect(() => {
    isInitialMountRef.current = false

    return () => {
      isInitialMountRef.current = true
    }
  }, [])
  // Reset itemRefs on close.
  useEffect(() => {
    if (!isOpen) {
      itemRefs.current = {}
    } else if (environment.document?.activeElement !== inputRef.current) {
      inputRef?.current?.focus()
    }
  }, [isOpen, environment])

  /* Event handler functions */
  const inputKeyDownHandlers = useMemo(
    () => ({
      ArrowDown(event) {
        event.preventDefault()
        dispatch({
          type: stateChangeTypes.InputKeyDownArrowDown,
          altKey: event.altKey,
          getItemNodeFromIndex,
        })
      },
      ArrowUp(event) {
        event.preventDefault()
        dispatch({
          type: stateChangeTypes.InputKeyDownArrowUp,
          altKey: event.altKey,
          getItemNodeFromIndex,
        })
      },
      Home(event) {
        if (!latest.current.state.isOpen) {
          return
        }

        event.preventDefault()
        itemProp,
        indexProp,
        latestProps.items,
        'Pass either item or index to getItemProps!',
      )

      const onSelectKey = isReactNative
        ? /* istanbul ignore next (react-native) */ 'onPress'
        : 'onClick'
      const customClickHandler = isReactNative
        ? /* istanbul ignore next (react-native) */ onPress
        : onClick

      const itemHandleMouseMove = () => {
        if (index === latestState.highlightedIndex) {
          return
        }
        shouldScrollRef.current = false
        dispatch({
          type: stateChangeTypes.ItemMouseMove,
          index,
          disabled,
        })
      }
      const itemHandleClick = () => {
        dispatch({
          type: stateChangeTypes.ItemClick,
          index,
        })
      }
      const itemHandleMouseDown = e => e.preventDefault()

      return {
        [refKey]: handleRefs(ref, itemNode => {
          if (itemNode) {
            itemRefs.current[elementIds.getItemId(index)] = itemNode
          }
        }),
        disabled,
        role: 'option',
        'aria-selected': `${index === latestState.highlightedIndex}`,
        id: elementIds.getItemId(index),
        ...(!disabled && {
          [onSelectKey]: callAllEventHandlers(
            customClickHandler,
            itemHandleClick,
          ),
        }),
        onMouseMove: callAllEventHandlers(onMouseMove, itemHandleMouseMove),
        onMouseDown: callAllEventHandlers(onMouseDown, itemHandleMouseDown),
        ...rest,
      }
    },
    [dispatch, latest, shouldScrollRef, elementIds],
  )

  const getToggleButtonProps = useCallback(
    ({onClick, onPress, refKey = 'ref', ref, ...rest} = {}) => {
      const latestState = latest.current.state
      const toggleButtonHandleClick = () => {
        dispatch({
          type: stateChangeTypes.ToggleButtonClick,
        })
      }

      return {
        [refKey]: handleRefs(ref, toggleButtonNode => {
          toggleButtonRef.current = toggleButtonNode
        }),
        'aria-controls': elementIds.menuId,
        'aria-expanded': latestState.isOpen,
        id: elementIds.toggleButtonId,
        tabIndex: -1,
        ...(!rest.disabled && {
          ...(isReactNative
            ? /* istanbul ignore next (react-native) */ {
                onPress: callAllEventHandlers(onPress, toggleButtonHandleClick),
              }
            : {
                onClick: callAllEventHandlers(onClick, toggleButtonHandleClick),
              }),
        }),
        ...rest,
      }
    },
    [dispatch, latest, elementIds],
  )
  const getInputProps = useCallback(
    (
      {
        onKeyDown,
        onChange,
        onInput,
        onFocus,
        onBlur,
        onChangeText,
        refKey = 'ref',
        ref,
        ...rest
      } = {},
      {suppressRefError = false} = {},
    ) => {
      setGetterPropCallInfo('getInputProps', suppressRefError, refKey, inputRef)

      const latestState = latest.current.state
      const inputHandleKeyDown = event => {
        const key = normalizeArrowKey(event)
        if (key && inputKeyDownHandlers[key]) {
          inputKeyDownHandlers[key](event)
        }
      }
      const inputHandleChange = event => {
        dispatch({
          type: stateChangeTypes.InputChange,
          inputValue: isReactNative
            ? /* istanbul ignore next (react-native) */ event.nativeEvent.text
            : event.target.value,
        })
      }
      const inputHandleBlur = () => {
        /* istanbul ignore else */
        if (
          latestState.isOpen &&
          !mouseAndTouchTrackersRef.current.isMouseDown
        ) {
          dispatch({
            type: stateChangeTypes.InputBlur,
            selectItem: true,
          })
        }
      }

  test('pageUp does not prevent the default event behavior with the menu closed', () => {
    renderCombobox()
    const toggleButton = getInput()
    const keyDownEvent = createEvent.keyDown(toggleButton, {key: 'PageUp'})

    fireEvent(toggleButton, keyDownEvent)

    expect(keyDownEvent.defaultPrevented).toBe(false)
  })

  test('pageDown jumps highlight down by 10 options', async () => {
    const initialHighlightedIndex = 12
    renderCombobox({
      isOpen: true,
      initialHighlightedIndex,
    })

    await keyDownOnInput('{PageDown}')

    expect(getInput()).toHaveAttribute(
      'aria-activedescendant',
      defaultIds.getItemId(initialHighlightedIndex + 10),
    )
  })

  test('pageDown jumps highlight the last option if highlightedIndex is closer than 10 indeces to the end', async () => {
    const initialHighlightedIndex = items.length - 5
    renderCombobox({
      isOpen: true,
      initialHighlightedIndex,
    })

    await keyDownOnInput('{PageDown}')

    expect(getInput()).toHaveAttribute(
      'aria-activedescendant',
      defaultIds.getItemId(items.length - 1),
    )
  })

  test('pageDown prevents the default event behavior with the menu open', () => {
    renderCombobox({isOpen: true})
    const toggleButton = getInput()
    const keyDownEvent = createEvent.keyDown(toggleButton, {
      key: 'PageDown',
    })

    fireEvent(toggleButton, keyDownEvent)

    expect(keyDownEvent.defaultPrevented).toBe(true)
  })

  test('pageDown does not prevent the default event behavior with the menu closed', () => {
    renderCombobox()
    const toggleButton = getInput()
    const keyDownEvent = createEvent.keyDown(toggleButton, {
      key: 'PageDown',
    })

    fireEvent(toggleButton, keyDownEvent)

    expect(keyDownEvent.defaultPrevented).toBe(false)
  })
})

describe('on blur', () => {
  test('the open menu will be closed and highlighted item will be selected', async () => {
    const initialHighlightedIndex = 2
    renderCombobox({
      initialIsOpen: true,
      initialHighlightedIndex,
    })

    await tab()

    expect(getItems()).toHaveLength(0)
    expect(getInput()).toHaveValue(items[initialHighlightedIndex])
  })

  test('the open menu will be closed and highlighted item will not be selected if the highlight by mouse leaves the menu', async () => {
    const initialHighlightedIndex = 2
    renderCombobox({
      initialIsOpen: true,
      initialHighlightedIndex,
    })

    await mouseMoveItemAtIndex(initialHighlightedIndex)
    await mouseLeaveItemAtIndex(initialHighlightedIndex)
    await tab()

    expect(getItems()).toHaveLength(0)
    expect(getInput()).toHaveValue('')
  })

  test('the value in the input will stay the same', async () => {
    const inputValue = 'test me'
    renderCombobox({
      initialIsOpen: true,
    })

    await changeInputValue(inputValue)
    await tab()

    expect(getInput()).toHaveValue(inputValue)
  })

  test('by mouse is not triggered if target is within downshift', () => {
    const stateReducer = jest.fn().mockImplementation(s => s)
    const {container} = renderCombobox({
      isOpen: true,
      highlightedIndex: 0,
      stateReducer,
    })
    const input = getInput()
    document.body.appendChild(container)

    fireEvent.mouseDown(input)
    fireEvent.mouseUp(input)

    expect(stateReducer).not.toHaveBeenCalled()

    fireEvent.mouseDown(document.body)
    fireEvent.mouseUp(document.body)

    expect(stateReducer).toHaveBeenCalledTimes(1)
    expect(stateReducer).toHaveBeenCalledWith(
      {
        highlightedIndex: 0,
        inputValue: '',
        isOpen: true,
        selectedItem: null,
      },
      expect.objectContaining({
        type: stateChangeTypes.InputBlur,
        changes: {
          highlightedIndex: -1,
          inputValue: '',
          isOpen: false,
          selectedItem: null,
        },
      }),
    )
  })

  test('by touch is not triggered if target is within downshift', () => {
    const stateReducer = jest.fn().mockImplementation(s => s)
    const {container} = renderCombobox({
      isOpen: true,
      highlightedIndex: 0,
      stateReducer,
    })
    const input = getInput()
    document.body.appendChild(container)

    fireEvent.touchStart(input)
    fireEvent.touchMove(input)
    fireEvent.touchEnd(input)

    expect(stateReducer).not.toHaveBeenCalled()

    fireEvent.touchStart(document.body)
    fireEvent.touchEnd(document.body)

    expect(stateReducer).toHaveBeenCalledTimes(1)
    expect(stateReducer).toHaveBeenCalledWith(
      {
        highlightedIndex: 0,
        inputValue: '',
        isOpen: true,
        selectedItem: null,
      },
      expect.objectContaining({
        type: stateChangeTypes.InputBlur,
        changes: {
          highlightedIndex: -1,
          inputValue: '',
          isOpen: false,
          selectedItem: null,
        },
      }),
    )
  })
})

